#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 5e5+5;
const int INF = 0x3f3f3f3f;
int n,m,k,ren[105],tk[105],g[105][105],fa[N];
int St,Ed,dis[N],Tim,res,flow;queue<int> q;
int tot=1,head[N],to[N],wei[N],nxt[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int FF(int u){return (fa[u]==u?u:fa[u]=FF(fa[u]));}
void Merge(int u,int v){u=FF(u),v=FF(v);if(u!=v)fa[u]=v;return;}
void Add_edge(int x,int y,int z){
    ++tot,to[tot]=y,wei[tot]=z;
    nxt[tot]=head[x],head[x]=tot;
    ++tot,to[tot]=x,wei[tot]=0;
    nxt[tot]=head[y],head[y]=tot;return;
}
bool BFS_Canit(){
    for(int i=1;i<=Ed;i++)dis[i]=0;
    while(!q.empty())q.pop();
    dis[St]=1,q.push(St);
    while(!q.empty()){
        int u=q.front();q.pop();
        for(int i=head[u];i;i=nxt[i]){
            int v=to[i],w=wei[i];
            if(!w||dis[v])continue;
            dis[v]=dis[u]+1;
            if(v==Ed)return 1;q.push(v);
        }
    }return 0;
}
int DFS_Cntflow(int u,int flow){
    if(u==Ed)return flow;int now=flow;
    for(int i=head[u];i;i=nxt[i]){
        if(now<=0)break;
        int v=to[i],w=wei[i];
        if(!w||dis[v]!=dis[u]+1)continue;
        int tmp=DFS_Cntflow(v,min(now,w));
        if(!tmp)dis[v]=0;
        else wei[i]-=tmp,wei[i^1]+=tmp,now-=tmp;
    }return flow-now;
}
int Sol_Dinic(){
    int res=0,flow=0;
    while(BFS_Canit())
        while(flow=DFS_Cntflow(St,INF))res+=flow;
    return res;
}
int main(){
    n=read(),m=read(),k=read();
    for(int i=1;i<=n+2;i++)fa[i]=i;
    for(int i=1;i<=m;i++){
        ren[i]=read(),tk[i]=read();
        for(int j=0;j<tk[i];j++){
            g[i][j]=read();
            if(g[i][j]==0)g[i][j]=n+1;
            if(g[i][j]==-1)g[i][j]=n+2;
            if(j)Merge(g[i][j-1],g[i][j]);
        }
    }if(FF(n+1)!=FF(n+2)){cout<<"0\n";return 0;}
    St=N-10,Ed=St+1;
    for(Tim=1;;Tim++){
        Add_edge(St,(Tim-1)*(n+1)+n+1,INF);
        for(int i=1;i<=m;i++){
            int x=(Tim-1)%tk[i],y=Tim%tk[i];
            if(g[i][x]==n+2)x=Ed;
            else x=(Tim-1)*(n+1)+g[i][x];
            if(g[i][y]==n+2)y=Ed;
            else y=Tim*(n+1)+g[i][y];
            Add_edge(x,y,ren[i]);
        }while(BFS_Canit())
            while(flow=DFS_Cntflow(St,INF))res+=flow;
        if(res>=k){cout<<Tim<<"\n";return 0;}
        for(int i=1;i<=n+1;i++)Add_edge((Tim-1)*(n+1)+i,Tim*(n+1)+i,INF);
    }
    return 0;
}
